args.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?causeLabel WHERE {
  ?person wdt:P69 wd:Q846173 ;
          wdt:P39 ?position ;
          wdt:P2872 [] ;
          wdt:P509 ?cause .
  ?position wdt:P31/wdt:P279* wd:Q13218630 .
  ?cause rdfs:label ?causeLabel .
  FILTER(LANG(?causeLabel) = "en")
}

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?person ?label WHERE {
  ?person wdt:P69 wd:Q846173 .
  ?person rdfs:label ?label .
  FILTER(LANG(?label) = "en")
}

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?person WHERE {
  ?person wdt:P69 wd:Q846173 .
  ?person wdt:P39 wd:Q13218630 .
  ?person wdt:P2872 [] .
}

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?causeLabel WHERE {
  ?person wdt:P69 wd:Q846173 ;
          wdt:P39 wd:Q13218630 ;
          wdt:P210 [] ;
          wdt:P509 ?cause .
  ?cause rdfs:label ?causeLabel .
  FILTER(LANG(?causeLabel) = "en")
}
